UPDATE sales_pipeline SET decision_factor = 'おそらく1ヶ月プランでご契約されるかなという印象。追加メンタリングはご予約いただいたが、早く教科書とか見て対策したいので明日か明後日には入会するか決めたいとのこと。思考速度めっちゃ速くて、かつ野村證券在職とのことなので少し圧ありますが、こちらが時折笑ったり柔和に接していると、結構笑ってくれます。' WHERE customer_id IN (SELECT ce.customer_id FROM customer_emails ce WHERE ce.email = 'mkaneko1234@gmail.com');
