UPDATE sales_pipeline SET decision_factor = 'mckのビヘイビア対策プランにかなり興味があるということで喜山さんを営業後追加メンタリングにアサインさせていただきました。ただ、あのビヘイビア対策は2回で完結してしまうので、次回は通常通りメンタリングを進めていただき、普段のカリキュラムでも通常通りのケースを出していただければと思います。そして、マッキンゼーのビヘイビア対策は追加のお支払いが必要とのことをお伝えください。' WHERE customer_id IN (SELECT ce.customer_id FROM customer_emails ce WHERE ce.email = 'naoya.mihara@gmail.com');
UPDATE sales_pipeline SET decision_factor = '特急プランで、かなり入会確度は高そう。ただ、年齢（32歳）もあってケース面接にそもそも進めるかわからないから、今受けてるbainのwebテスト次第で決める。その結果が出るのが4/4だからそこで追加メンタリングを入れた。あと、思考速度めっちゃ早くて内容も鋭い。あと、話すのがめっちゃ好きそうで仲良くなった。' WHERE customer_id IN (SELECT ce.customer_id FROM customer_emails ce WHERE ce.email = 'irohasu0407@gmail.com');
